package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import scala.util.{Try, Using}
import java.io.File
import java.nio.file.{Path, Paths}

@Singleton
class FileController @Inject()(val controllerComponents: ControllerComponents) extends BaseController {

  // Fixed base directory for file uploads - canonicalized once at startup
  private val BASE_UPLOAD_DIR: Path = Paths.get("uploads").toAbsolutePath.normalize()

  /**
   * Serves a file from the uploads directory.
   * Supports subdirectories, e.g., /files/images/photo.png
   * 
   * The filename parameter can contain forward slashes for subdirectory access.
   */
  def serveFile(filename: String): Action[AnyContent] = Action { implicit request =>
    validateAndResolvePath(filename) match {
      case Left(errorMessage) =>
        Forbidden(s"Access denied: $errorMessage")
      case Right(resolvedFile) =>
        if (!resolvedFile.exists()) {
          NotFound(s"File not found")
        } else if (!resolvedFile.isFile) {
          BadRequest("Requested path is not a file")
        } else if (!resolvedFile.canRead) {
          Forbidden("File is not readable")
        } else {
          readFileContent(resolvedFile) match {
            case Right(content) =>
              Ok(content).as(guessContentType(resolvedFile.getName))
            case Left(error) =>
              InternalServerError(s"Error reading file")
          }
        }
    }
  }

  /**
   * Validates and resolves the user-supplied filename against the base upload directory.
   * 
   * Security measures:
   * 1. Rejects null/empty/blank filenames
   * 2. Rejects absolute paths
   * 3. Rejects null bytes
   * 4. Canonicalizes the resolved path to eliminate traversal sequences
   * 5. Verifies the canonical path starts with the canonical base directory
   */
  private def validateAndResolvePath(filename: String): Either[String, File] = {
    // Reject null, empty, or blank filenames
    if (filename == null || filename.trim.isEmpty) {
      return Left("Filename must not be empty")
    }

    // Reject null bytes which can be used to truncate paths
    if (filename.contains('\u0000')) {
      return Left("Invalid characters in filename")
    }

    // Reject absolute paths (Unix and Windows style)
    if (filename.startsWith("/") || filename.startsWith("\\")) {
      return Left("Absolute paths are not allowed")
    }

    // Reject Windows-style absolute paths like C:\, D:/, etc.
    if (filename.length >= 2 && filename.charAt(1) == ':') {
      return Left("Absolute paths are not allowed")
    }

    // Resolve the path against the base directory
    val requestedPath: Path = BASE_UPLOAD_DIR.resolve(filename)

    // Canonicalize (normalize + resolve symlinks) to get the true filesystem path
    val canonicalBase: String = BASE_UPLOAD_DIR.toFile.getCanonicalPath
    val canonicalRequested: String = requestedPath.toFile.getCanonicalPath

    // Verify the canonical path is within the base directory
    // We check for exact match (the base dir itself) or that it starts with base dir + separator
    // to prevent matching "uploads2" when base is "uploads"
    if (canonicalRequested == canonicalBase) {
      Left("Cannot serve a directory")
    } else if (!canonicalRequested.startsWith(canonicalBase + File.separator)) {
      Left("Path traversal detected - access denied")
    } else {
      Right(new File(canonicalRequested))
    }
  }

  /**
   * Reads file content safely using Using for automatic resource management.
   */
  private def readFileContent(file: File): Either[String, String] = {
    Using(Source.fromFile(file, "UTF-8")) { source =>
      source.mkString
    }.toEither.left.map(_.getMessage)
  }

  /**
   * Guesses the content type based on file extension.
   */
  private def guessContentType(filename: String): String = {
    val extension = filename.lastIndexOf('.') match {
      case -1 => ""
      case i  => filename.substring(i + 1).toLowerCase
    }

    extension match {
      case "html" | "htm" => "text/html; charset=utf-8"
      case "css"          => "text/css; charset=utf-8"
      case "js"           => "application/javascript; charset=utf-8"
      case "json"         => "application/json; charset=utf-8"
      case "xml"          => "application/xml; charset=utf-8"
      case "txt"          => "text/plain; charset=utf-8"
      case "csv"          => "text/csv; charset=utf-8"
      case "md"           => "text/markdown; charset=utf-8"
      case "png"          => "image/png"
      case "jpg" | "jpeg" => "image/jpeg"
      case "gif"          => "image/gif"
      case "svg"          => "image/svg+xml"
      case "pdf"          => "application/pdf"
      case "zip"          => "application/zip"
      case _              => "application/octet-stream"
    }
  }
}